## 5. 头像系统 (Avatar System)

### 5.1 头像组件

```dart
class MessageAvatar extends StatelessWidget {
  final String? imageUrl;
  final String? name;
  final double size;
  final bool showStatus;
  final AvatarStatus? status;

  @override
  Widget build(BuildContext context) {
    return SizedBox(
      width: size,
      height: size,
      child: Stack(
        children: [
          // 头像图片
          CircleAvatar(
            radius: size / 2,
            backgroundImage: imageUrl != null ? NetworkImage(imageUrl!) : null,
            backgroundColor: Theme.of(context).colorScheme.surfaceContainerHigh,
            child: imageUrl == null
                ? Text(
                    name?.substring(0, 1).toUpperCase() ?? '?',
                    style: TextStyle(
                      color: Theme.of(context).colorScheme.onSurfaceVariant,
                      fontSize: size * 0.4,
                    ),
                  )
                : null,
          ),
          // 在线状态指示器
          if (showStatus &amp;&amp; status != null)
            Positioned(
              bottom: 0,
              right: 0,
              child: AvatarStatusIndicator(status: status!),
            ),
        ],
      ),
    );
  }
}
```

### 5.2 状态指示器

```dart
enum AvatarStatus {
  online,
  offline,
  busy,
}

class AvatarStatusIndicator extends StatelessWidget {
  final AvatarStatus status;

  @override
  Widget build(BuildContext context) {
    Color statusColor;

    switch (status) {
      case AvatarStatus.online:
        statusColor = Theme.of(context).colorScheme.success;
        break;
      case AvatarStatus.busy:
        statusColor = Theme.of(context).colorScheme.warning;
        break;
      case AvatarStatus.offline:
      default:
        statusColor = Theme.of(context).colorScheme.onSurfaceVariant;
    }

    return Container(
      width: 14,
      height: 14,
      decoration: BoxDecoration(
        color: statusColor,
        shape: BoxShape.circle,
        border: Border.all(
          color: Theme.of(context).colorScheme.surfaceContainerHigh,
          width: 2,
        ),
      ),
    );
  }
}
```

