## 6. NavigationPane (面板导航)

### 6.1 基础实现

```dart
class NavigationPane extends StatelessWidget {
  final int selectedIndex;
  final ValueChanged&lt;int&gt; onDestinationSelected;

  @override
  Widget build(BuildContext context) {
    return Container(
      width: 280,
      color: Theme.of(context).colorScheme.surfaceContainer,
      child: Column(
        children: [
          // 头部
          Container(
            padding: EdgeInsets.all(16),
            child: Text(
              'Clotho',
              style: Theme.of(context).textTheme.headlineSmall?.copyWith(
                color: Theme.of(context).colorScheme.primary,
              ),
            ),
          ),
          Divider(
            color: Theme.of(context).colorScheme.divider,
          ),
          // 导航项
          Expanded(
            child: ListView(
              padding: EdgeInsets.symmetric(vertical: 8),
              children: [
                _buildNavigationItem(
                  context,
                  icon: Icons.chat_bubble_outline,
                  selectedIcon: Icons.chat_bubble,
                  label: '对话',
                  index: 0,
                  selectedIndex: selectedIndex,
                  onTap: onDestinationSelected,
                ),
                _buildNavigationItem(
                  context,
                  icon: Icons.book_outline,
                  selectedIcon: Icons.book,
                  label: '世界书',
                  index: 1,
                  selectedIndex: selectedIndex,
                  onTap: onDestinationSelected,
                ),
                _buildNavigationItem(
                  context,
                  icon: Icons.person_outline,
                  selectedIcon: Icons.person,
                  label: '角色卡',
                  index: 2,
                  selectedIndex: selectedIndex,
                  onTap: onDestinationSelected,
                ),
                Divider(
                  color: Theme.of(context).colorScheme.divider,
                ),
                _buildNavigationItem(
                  context,
                  icon: Icons.settings_outlined,
                  selectedIcon: Icons.settings,
                  label: '设置',
                  index: 3,
                  selectedIndex: selectedIndex,
                  onTap: onDestinationSelected,
                ),
              ],
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildNavigationItem(
    BuildContext context, {
    required IconData icon,
    required IconData selectedIcon,
    required String label,
    required int index,
    required int selectedIndex,
    required ValueChanged&lt;int&gt; onTap,
  }) {
    final isSelected = index == selectedIndex;

    return ListTile(
      leading: Icon(
        isSelected ? selectedIcon : icon,
        color: isSelected
            ? Theme.of(context).colorScheme.primary
            : Theme.of(context).colorScheme.onSurfaceVariant,
      ),
      title: Text(
        label,
        style: TextStyle(
          color: isSelected
              ? Theme.of(context).colorScheme.primary
              : Theme.of(context).colorScheme.onSurface,
        ),
      ),
      selected: isSelected,
      onTap: () =&gt; onTap(index),
      selectedTileColor: Theme.of(context).colorScheme.primaryContainer.withOpacity(0.12),
    );
  }
}
```

