## 4. 底部面板 (Bottom Sheet)

### 4.1 基础实现

```dart
class ClothoBottomSheet extends StatelessWidget {
  final String? title;
  final Widget content;
  final List&lt;Widget&gt;? actions;

  @override
  Widget build(BuildContext context) {
    return Container(
      decoration: BoxDecoration(
        color: Theme.of(context).colorScheme.surfaceContainer,
        borderRadius: BorderRadius.vertical(top: Radius.circular(16)),
      ),
      child: Column(
        mainAxisSize: MainAxisSize.min,
        children: [
          if (title != null) ...[
            Padding(
              padding: EdgeInsets.all(16),
              child: Row(
                children: [
                  Expanded(
                    child: Text(
                      title!,
                      style: Theme.of(context).textTheme.titleLarge,
                    ),
                  ),
                  IconButton(
                    icon: Icon(Icons.close),
                    onPressed: () =&gt; Navigator.of(context).pop(),
                  ),
                ],
              ),
            ),
            Divider(color: Theme.of(context).colorScheme.divider),
          ],
          Flexible(
            child: SingleChildScrollView(
              padding: EdgeInsets.all(16),
              child: content,
            ),
          ),
          if (actions != null) ...[
            Divider(color: Theme.of(context).colorScheme.divider),
            Padding(
              padding: EdgeInsets.all(16),
              child: Row(
                mainAxisAlignment: MainAxisAlignment.end,
                children: actions!,
              ),
            ),
          ],
        ],
      ),
    );
  }

  static Future&lt;T?&gt; show&lt;T&gt;({
    required BuildContext context,
    String? title,
    required Widget content,
    List&lt;Widget&gt;? actions,
    bool isScrollControlled = true,
  }) {
    return showModalBottomSheet&lt;T&gt;(
      context: context,
      isScrollControlled: isScrollControlled,
      backgroundColor: Colors.transparent,
      builder: (context) =&gt; ClothoBottomSheet(
        title: title,
        content: content,
        actions: actions,
      ),
    );
  }
}
```

### 4.2 响应式底部面板

```dart
class ResponsiveBottomSheet extends StatelessWidget {
  final String title;
  final Widget content;
  final List&lt;Widget&gt; actions;

  @override
  Widget build(BuildContext context) {
    final isMobile = MediaQuery.of(context).size.width &lt; 600;

    if (isMobile) {
      // 移动端：底部面板
      return ClothoBottomSheet(
        title: title,
        content: content,
        actions: actions,
      );
    } else {
      // 桌面端：对话框
      return ResponsiveDialog(
        title: title,
        content: content,
        actions: actions,
      );
    }
  }

  static Future&lt;T?&gt; show&lt;T&gt;({
    required BuildContext context,
    required String title,
    required Widget content,
    required List&lt;Widget&gt; actions,
  }) {
    final isMobile = MediaQuery.of(context).size.width &lt; 600;

    if (isMobile) {
      return showModalBottomSheet&lt;T&gt;(
        context: context,
        backgroundColor: Colors.transparent,
        builder: (context) =&gt; ClothoBottomSheet(
          title: title,
          content: content,
          actions: actions,
        ),
      );
    } else {
      return showDialog&lt;T&gt;(
        context: context,
        builder: (context) =&gt; ResponsiveDialog(
          title: title,
          content: content,
          actions: actions,
        ),
      );
    }
  }
}
```

