# Inspector 组件 (Inspector Component)

**版本**: 1.0.0
**日期**: 2026-02-11
**状态**: Draft
**参考**: `00_active_specs/presentation/README.md`

---

## 1. 概述 (Overview)

Inspector 是 Clotho Control 区域的核心组件，提供对 `Mnemosyne` 状态树的只读可视化界面。本规范定义 Inspector 的结构、Schema 驱动渲染和数据检视功能。

### 1.1 设计原则

| 原则 | 说明 |
| :--- | :--- |
| **只读访问** | Inspector 只能查看状态，不能直接修改 |
| **Schema 驱动** | 支持自定义 Schema 定义数据展示方式 |
| **实时同步** | 监听 Mnemosyne 状态流，实时更新 |
| **可扩展** | 支持第三方自定义渲染器 |

---

## 2. 组件结构 (Component Structure)

### 2.1 基础结构

```dart
class Inspector extends StatefulWidget {
  @override
  _InspectorState createState() =&gt; _InspectorState();
}

class _InspectorState extends State&lt;Inspector&gt; {
  final StreamSubscription _subscription;
  Map&lt;String, dynamic&gt; _stateTree = {};
  String _selectedPath = '';

  @override
  void initState() {
    super.initState();
    // 订阅 Mnemosyne 状态流
    _subscription = Mnemosyne.stateStream.listen((snapshot) {
      setState(() {
        _stateTree = snapshot;
      });
    });
  }

  @override
  void dispose() {
    _subscription.cancel();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return Container(
      width: 320,
      color: Theme.of(context).colorScheme.surfaceContainer,
      child: Column(
        children: [
          // 头部
          InspectorHeader(
            title: '数据检视器',
            onRefresh: () {
              // 刷新状态
            },
          ),
          Divider(color: Theme.of(context).colorScheme.divider),
          // 状态树
          Expanded(
            child: StateTreeViewer(
              stateTree: _stateTree,
              selectedPath: _selectedPath,
              onPathSelected: (path) {
                setState(() {
                  _selectedPath = path;
                });
              },
            ),
          ),
          // 详情面板
          if (_selectedPath.isNotEmpty)
            InspectorDetailPanel(
              path: _selectedPath,
              value: _getValueAtPath(_selectedPath),
            ),
        ],
      ),
    );
  }

  dynamic _getValueAtPath(String path) {
    final parts = path.split('.');
    dynamic current = _stateTree;

    for (final part in parts) {
      if (current is Map &amp;&amp; current.containsKey(part)) {
        current = current[part];
      } else {
        return null;
      }
    }

    return current;
  }
}
```

---

## 3. StateTreeViewer (状态树查看器)

### 3.1 基础实现

```dart
class StateTreeViewer extends StatelessWidget {
  final Map&lt;String, dynamic&gt; stateTree;
  final String selectedPath;
  final ValueChanged&lt;String&gt; onPathSelected;

  @override
  Widget build(BuildContext context) {
    return ListView(
      padding: EdgeInsets.all(8),
      children: [
        _buildTreeItem(
          context,
          name: 'root',
          value: stateTree,
          path: '',
          level: 0,
        ),
      ],
    );
  }

  Widget _buildTreeItem(
    BuildContext context, {
    required String name,
    required dynamic value,
    required String path,
    required int level,
  }) {
    final fullPath = path.isEmpty ? name : '$path.$name';
    final isSelected = fullPath == selectedPath;
    final hasChildren = value is Map;

    return Container(
      padding: EdgeInsets.only(left: level * 16.0),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          // 树节点
          InkWell(
            onTap: () =&gt; onPathSelected(fullPath),
            child: Container(
              padding: EdgeInsets.symmetric(
                horizontal: 8,
                vertical: 6,
              ),
              decoration: BoxDecoration(
                color: isSelected
                    ? Theme.of(context).colorScheme.primaryContainer.withOpacity(0.3)
                    : Colors.transparent,
                borderRadius: BorderRadius.circular(4),
              ),
              child: Row(
                children: [
                  Icon(
                    hasChildren
                        ? (isExpanded(fullPath) ? Icons.expand_more : Icons.chevron_right)
                        : Icons.circle,
                    size: 16,
                    color: Theme.of(context).colorScheme.onSurfaceVariant,
                  ),
                  SizedBox(width: 8),
                  Expanded(
                    child: Text(
                      name,
                      style: TextStyle(
                        color: Theme.of(context).colorScheme.onSurface,
                        fontWeight: isSelected ? FontWeight.bold : FontWeight.normal,
                      ),
                    ),
                  ),
                  if (!hasChildren)
                    Text(
                      '(${_getValueType(value)})',
                      style: TextStyle(
                        color: Theme.of(context).colorScheme.onSurfaceVariant,
                        fontSize: 12,
                      ),
                    ),
                ],
              ),
            ),
          ),
          // 子节点
          if (hasChildren &amp;&amp; isExpanded(fullPath))
            ..._buildChildren(value, fullPath, level + 1),
        ],
      ),
    );
  }

  List&lt;Widget&gt; _buildChildren(
    Map&lt;String, dynamic&gt; map,
    String path,
    int level,
  ) {
    return map.entries
        .map((entry) =&gt; _buildTreeItem(
              context,
              name: entry.key,
              value: entry.value,
              path: path,
              level: level,
            ))
        .toList();
  }

  String _getValueType(dynamic value) {
    if (value is String) return 'String';
    if (value is int) return 'Int';
    if (value is double) return 'Double';
    if (value is bool) return 'Boolean';
    if (value is List) return 'Array';
    if (value is Map) return 'Object';
    return 'Unknown';
  }

  bool isExpanded(String path) {
    // 简化实现，实际应该维护展开状态
    return false;
  }
}
```

---

## 4. Schema 驱动渲染 (Schema-Driven Rendering)

### 4.1 Schema 定义

```dart
class UISchema {
  final String type; // 'table', 'card', 'list', 'tree'
  final Map&lt;String, dynamic&gt;? config;

  UISchema({
    required this.type,
    this.config,
  });

  factory UISchema.fromJson(Map&lt;String, dynamic&gt; json) {
    return UISchema(
      type: json['type'] ?? 'tree',
      config: json['config'],
    );
  }
}
```

### 4.2 Schema 渲染器

```dart
class SchemaDrivenRenderer extends StatelessWidget {
  final String path;
  final dynamic value;
  final UISchema? schema;

  @override
  Widget build(BuildContext context) {
    final renderer = schema ?? UISchema(type: 'tree');

    switch (renderer.type) {
      case 'table':
        return TableRenderer(
          value: value,
          config: renderer.config,
        );
      case 'card':
        return CardRenderer(
          value: value,
          config: renderer.config,
        );
      case 'list':
        return ListRenderer(
          value: value,
          config: renderer.config,
        );
      case 'tree':
      default:
        return TreeRenderer(
          value: value,
        );
    }
  }
}
```

### 4.3 表格渲染器

```dart
class TableRenderer extends StatelessWidget {
  final dynamic value;
  final Map&lt;String, dynamic&gt;? config;

  @override
  Widget build(BuildContext context) {
    if (value is! List) {
      return Text('数据不是数组');
    }

    final data = value as List;
    final columns = config?['columns'] as List&lt;String&gt;? ?? [];

    return Container(
      decoration: BoxDecoration(
        color: Theme.of(context).colorScheme.surfaceContainerLow,
        borderRadius: BorderRadius.circular(8),
      ),
      child: SingleChildScrollView(
        scrollDirection: Axis.horizontal,
        child: DataTable(
          columns: columns
              .map((col) =&gt; DataColumn(
                    label: Text(col),
                  ))
              .toList(),
          rows: data
              .map((row) =&gt; DataRow(
                    cells: columns
                        .map((col) =&gt; DataCell(
                              Text(row[col]?.toString() ?? ''),
                            ))
                        .toList(),
                  ))
              .toList(),
        ),
      ),
    );
  }
}
```

