## 4. Intent 转换 (Intent Conversion)

### 4.1 Intent 定义

```dart
enum IntentType {
  sendMessage,
  editMessage,
  deleteMessage,
  regenerate,
  retry,
}

class Intent {
  final String id;
  final IntentType type;
  final Map&lt;String, dynamic&gt; data;

  Intent({
    required this.id,
    required this.type,
    required this.data,
  });

  Map&lt;String, dynamic&gt; toJson() {
    return {
      'id': id,
      'type': type.toString(),
      'data': data,
    };
  }
}
```

### 4.2 Intent 生成器

```dart
class IntentGenerator {
  static Intent sendMessage({
    required String content,
    String? characterId,
  }) {
    return Intent(
      id: generateId(),
      type: IntentType.sendMessage,
      data: {
        'content': content,
        'characterId': characterId,
        'timestamp': DateTime.now().toIso8601String(),
      },
    );
  }

  static Intent editMessage({
    required String messageId,
    required String content,
  }) {
    return Intent(
      id: generateId(),
      type: IntentType.editMessage,
      data: {
        'messageId': messageId,
        'content': content,
        'timestamp': DateTime.now().toIso8601String(),
      },
    );
  }

  static Intent deleteMessage({
    required String messageId,
  }) {
    return Intent(
      id: generateId(),
      type: IntentType.deleteMessage,
      data: {
        'messageId': messageId,
        'timestamp': DateTime.now().toIso8601String(),
      },
    );
  }

  static Intent regenerate({
    required String messageId,
  }) {
    return Intent(
      id: generateId(),
      type: IntentType.regenerate,
      data: {
        'messageId': messageId,
        'timestamp': DateTime.now().toIso8601String(),
      },
    );
  }

  static String generateId() {
    return 'intent_${DateTime.now().millisecondsSinceEpoch}_${Random().nextInt(1000)}';
  }
}
```

