class StatusBarButtonHandler {
  final InputDraftController _draftController;

  StatusBarButtonHandler(this._draftController);

  /// 处理状态栏按钮点击
  void handleStatusButtonClick(StatusBarButton button) {
    switch (button.type) {
      case StatusButtonType.action:
