  final Widget child;

  @override
  Widget build(BuildContext context) {
    return PageTransitionsTheme(
      data: PageTransitionsTheme(
        builders: {
          TargetPlatform.android: ZoomPageTransitionsBuilder(),
          TargetPlatform.windows: FadeUpwardsPageTransitionsBuilder(),
        },
      ),
      child: child,
    );
  }
}
```

### 4.3 淡入淡出过渡

```dart
class FadePageTransition extends PageRouteBuilder {
  final Widget child;

  FadePageTransition({required this.child})
      : super(
          pageBuilder: (context, animation, secondaryAnimation) {
            return FadeTransition(
              opacity: animation,
              child: child,
            );
          },
          transitionDuration: ClothoDuration.medium,
        );
}
```

---

## 5. 组件动画 (Component Animations)

### 5.1 消息气泡动画

```dart
class AnimatedMessageBubble extends StatefulWidget {
  final Message message;

  @override
  _AnimatedMessageBubbleState createState() =&gt; _AnimatedMessageBubbleState();
}

class _AnimatedMessageBubbleState extends State&lt;AnimatedMessageBubble&gt;
    with SingleTickerProviderStateMixin {
  late AnimationController _controller;
  late Animation&lt;double&gt; _opacityAnimation;
  late Animation&lt;double&gt; _slideAnimation;

  @override
  void initState() {
    super.initState();
    _controller = AnimationController(
      duration: ClothoDuration.medium,
      vsync: this,
    );

    _opacityAnimation = Tween&lt;double&gt;(
      begin: 0.0,
      end: 1.0,
    ).animate(CurvedAnimation(
      parent: _controller,
      curve: ClothoCurve.emphasizedDecelerate,
    ));

    _slideAnimation = Tween&lt;double&gt;(
      begin: 20.0,
      end: 0.0,
    ).animate(CurvedAnimation(
      parent: _controller,
      curve: ClothoCurve.emphasizedDecelerate,
    ));

    _controller.forward();
  }

  @override
  void dispose() {
    _controller.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return FadeTransition(
      opacity: _opacityAnimation,
      child: SlideTransition(
        position: Tween&lt;Offset&gt;(
          begin: Offset(0, 1),
          end: Offset.zero,
        ).animate(_controller),
        child: MessageBubble(message: widget.message),
      ),
    );
  }
}
```

### 5.2 输入框动画

```dart
class AnimatedInputField extends StatefulWidget {
  @override
  _AnimatedInputFieldState createState() =&gt; _AnimatedInputFieldState();
}

class _AnimatedInputFieldState extends State&lt;AnimatedInputField&gt; {
  bool _isFocused = false;

  @override
  Widget build(BuildContext context) {
    return AnimatedContainer(
      duration: ClothoDuration.fast,
      curve: ClothoCurve.standard,
      decoration: BoxDecoration(
        color: _isFocused
            ? Theme.of(context).colorScheme.primaryContainer.withOpacity(0.2)
            : Colors.transparent,
        borderRadius: BorderRadius.circular(24),
        border: Border.all(
          color: _isFocused
              ? Theme.of(context).colorScheme.primary
              : Colors.transparent,
          width: 2,
        ),
      ),
      child: Focus(
        onFocusChange: (hasFocus) {
          setState(() {
            _isFocused = hasFocus;
          });
        },
        child: TextField(
          decoration: InputDecoration(
            border: InputBorder.none,
            hintText: '输入消息...',
          ),
        ),
      ),
    );
  }
}
```

